type TriggersProxy struct {
	gateway.UnimplementedTriggersServer
	client gateway.TriggersClient
}

func init() {
	proxyutil.Register(&gateway.Triggers_ServiceDesc, NewTriggersProxy)
}
func NewTriggersProxy(cc grpc.ClientConnInterface) gateway.TriggersServer {
	return &TriggersProxy{client: gateway.NewTriggersClient(cc)}
}
func (p *TriggersProxy) OnTrigger(ctx context.Context, in *v1alpha.TriggerEvent) (*gateway.TriggerResponse, error) {
	return proxyutil.ProxyMethod[v1alpha.TriggerEvent, gateway.TriggerResponse](p.client.OnTrigger)(ctx, in)
}
func (p *TriggersProxy) OnFanOut(ctx context.Context, in *v1alpha.TriggerEvent) (*gateway.TriggerFanOutResponse, error) {
	return proxyutil.ProxyMethod[v1alpha.TriggerEvent, gateway.TriggerFanOutResponse](p.client.OnFanOut)(ctx, in)
}
func (p *TriggersProxy) OnInvoke(ctx context.Context, in *gateway.TriggerInvocation) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[gateway.TriggerInvocation, emptypb.Empty](p.client.OnInvoke)(ctx, in)
}
func (p *TriggersProxy) OnInstall(ctx context.Context, in *installation.InstallationInfo) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[installation.InstallationInfo, emptypb.Empty](p.client.OnInstall)(ctx, in)
}
func (p *TriggersProxy) OnUninstall(ctx context.Context, in *installation.InstallationInfo) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[installation.InstallationInfo, emptypb.Empty](p.client.OnUninstall)(ctx, in)
}
func (p *TriggersProxy) OnInstallChanged(ctx context.Context, in *installation.InstallationInfo) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[installation.InstallationInfo, emptypb.Empty](p.client.OnInstallChanged)(ctx, in)
}
